head.script:
//-------------------------------------------------------------------------
// PGM명 : 유류입고등록 (tr_270_05_01b)
// 작성자 : 송정희
// 최초작성일자 : 2026-01-16
//-------------------------------------------------------------------------
scwin.strCurDate = ""; // 작업날짜
scwin.strCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
scwin.strPreDate = scwin.strCurDate.toString().substring(0,6) + "01"; //당월 1일
scwin.vSelfTransYn = "";
scwin.vInDt = "";
scwin.vHomeClsCd = "";
scwin.vOilStatClntNo = "";

//-------------------------------------------------------------------------
// onpageload
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	lc_homeClsCd.setValue("LO");

	const codeOptions = [
        { grpCd : "ZZ205", compID : "lc_homeClsCd, gr_tr274:homeClsCd ",opt :{"range" : "2,TR"}},     // 소속구분
        { grpCd : "TL113", compID : "lc_payClsCd, gr_tr274:payClsCd" }          // 거래구분 
    ];
    $c.data.setCommonCode(codeOptions);      
    var selfTransYn_jsonData = [{"selfTransYn":"9", "selfTransYnNm":"전체"},
                                {"selfTransYn":"0", "selfTransYnNm":"정유사운송"},
                                {"selfTransYn":"1", "selfTransYnNm":"자가운송"} 
                                ]; 
    ds_selfTransYn.setJSON(selfTransYn_jsonData); // 운송구분

    const LxCodeOptions = [
        {
            method: "getLuxeComboData",
            param1: "PsCommonEBC",
            param2: "retriveOilStatClsCd2",
            compID: "lc_oilStatClsCd, gr_tr274:oilStatClsCd"
        },  // 주유소구분
        {
            method: "getLuxeComboData",
            param1: "PsCommonEBC",
            param2: "retriveOilStatByClsCd",
            compID: "gr_tr274:oilStatClntNo"
        },  // 주유소
        {
            method: "getLuxeComboData",
            param1: "PsCommonEBC",
            param2: "retrieveOilCompany",
            compID: "lc_oilCoClntNo, gr_tr274:oilCoClntNo"
        }   // 정유사   
    ];
    $c.data.setGauceUtil(LxCodeOptions);    
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    ed_stDt.setValue(scwin.strPreDate);
    ed_endDt.setValue(scwin.strCurDate);
    ed_stDt.focus();  	

    scwin.lc_oilStatClsCd_onchange();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {

	//날짜 체크 start---------------------------------------
	var stDt = ed_stDt.getValue();
	var endDt= ed_endDt.getValue();
	if( stDt == "        ") {
		dma_search.set("stDt" ,"");
	}
	if( endDt == "        ") {
		dma_search.set("endDt" , "");
	}

    if( stDt == "" || endDt == "" ) {    
        $c.win.alert("입고일자는 필수 입력 항목입니다.");        
        if( stDt == "" ) {
            udc_stDt.inputFocus("ipt_from");
        } else {
            udc_stDt.inputFocus("ipt_to");
        }
        return;
    }

	var ls_stDt  = dma_search.set("stDt" , "");
	var ls_endDt = dma_search.set("endDt", "" );
	if( ls_endDt == "" || ls_endDt == null ) {	
	} 
	else {

        if( !$c.gus.cfIsAfterDate(ed_stDt.getValue(), ed_endDt.getValue()) ) {
			$c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
			ed_stDt.focus();
			return;
		}
	}
    scwin.vInDt = ed_endDt.getValue();
    scwin.vHomeClsCd = lc_homeClsCd.getValue();
    scwin.vOilStatClntNo = lc_oilStatClntNo.getValue();

    dma_search.set("stDt" , ed_stDt.getValue());
	dma_search.set("endDt" , ed_endDt.getValue());
    dma_search.set("homeClsCd", lc_homeClsCd.getValue());
    dma_search.set("oilStatClsCd", lc_oilStatClsCd.getValue());
    dma_search.set("oilStatClntNo", lc_oilStatClntNo.getValue());
    dma_search.set("selfTransYn", lc_selfTransYn.getValue());
    dma_search.set("transClntNo", ed_transClntNo.getValue());
    dma_search.set("oilCoClntNo", lc_oilCoClntNo.getValue());
    dma_search.set("payClsCd", lc_payClsCd.getValue());

	//날짜 체크 end---------------------------------------
    $c.sbm.execute(sbm_master);
};

scwin.sbm_master_submitdone = function (e) {
    totalRows.setValue(ds_tr274.getTotalRow());
    if( ds_tr274.getTotalRow() == 0 ) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    } else {
        scwin.f_JobCloseYN();
    }   
};

//-------------------------------------------------------------------------
// 	팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch, row) {
    scwin.isOpenPopup = true;
	var rtnList  = new Array();
	switch (disGubun) {
	    case 1: // 운송거래처
            udc_transClntNo.cfCommonPopUp(scwin.udc_transClntNo_callBackFunc
                        , pCode, pName
                        , "T"                             // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , "F"                             // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );          
		    break;

        case 2: // Grid 운송거래처
            udc_comCode_grid_transClntNo.setSelectId('retrieveClntEmpNoList');
            return await udc_comCode_grid_transClntNo.cfCommonPopUpAsync(
			    function(ret) { scwin.udc_comCode_grid_transClntNo_callback(ret, row) }  	// XML상의 SELECT ID
									,pCode							// 화면에서의 ??? Code Element의	Value
									,pName							// 화면에서의 ??? Name Element의	Value
									,'T'							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
									,null							// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
									,null							// Title순서
									,null							// 보여주는 각 컬럼들의 폭
									,null							// 컬럼중에서 숨기는	컬럼 지정
									,null							// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
									,null							// POP-UP뛰을때 원도우의	사용자 정의	폭
									,null							// POP-UP뛰을때 우도우의	사용자 정의	높이
									,null							// 윈도우 위치 Y좌표
									,null							// 윈도우 위치 X좌표
									,null							// 중복체크여부	("F")
									,null							// 전체검색허용여부	("F")
									,null		                    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
									); 

			break;	
  		default:
			break;
  	}
    scwin.isOpenPopup = true;
};

//------------------------------------------------------------------------- 
// 검색조건 : 운송거래처 callback
//------------------------------------------------------------------------- 
scwin.udc_transClntNo_callBackFunc = function (ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {    
        ed_transClntNo.setValue(ret[0]);
        ed_transClntNm.setValue(ret[1]);
	} else {
        ed_transClntNo.setValue("");
        ed_transClntNm.setValue("");
	}         
};

//-------------------------------------------------------------------------
// Grid : 운송거래처 callback
//-------------------------------------------------------------------------
scwin.udc_comCode_grid_transClntNo_callback = function(rtnList, rowIndex) {
    if ( rtnList != null && rtnList[0] != "N/A") {
        ds_tr274.setCellData(rowIndex,"transClntNo", rtnList[0]);        
        ds_tr274.setCellData(rowIndex,"transClntNm", rtnList[1]);
    } else {
        ds_tr274.setCellData(rowIndex,"transClntNo", "");
        ds_tr274.setCellData(rowIndex,"transClntNm", "");
    }
};

//-------------------------------------------------------------------------
// Grid 이미지 클릭시 발생 이벤트
//-------------------------------------------------------------------------
scwin.gr_tr274_ontextimageclick = function (rowIndex, columnIndex) {    
    let colId = gr_tr274.getColumnID(columnIndex);
    let value = ds_tr274.getCellData(rowIndex,colId);
    if (scwin.isOpenPopup != true) {
        if (colId == "transClntNo") {   // 운송거래처
            let vTransClntNo = ds_tr274.getCellData(rowIndex, "transClntNo");
            scwin.f_openCommonPopUp(2, vTransClntNo, "", "T", "T", rowIndex);
        }    
    }
    setTimeout(function() {
        scwin.isOpenPopup = false;
    }, 100)
};

//-------------------------------------------------------------------------
// Grid 셀 편집모드 종료시 발생 이벤트
//-------------------------------------------------------------------------
scwin.gr_tr274_onafteredit = function (rowIndex, columnIndex, value) {
    /* let colId = gr_tr274.getColumnID(columnIndex);
    if( colId == "transClntNo" ) {  // 운송거래처
        let vTransClntNo = ds_tr274.getCellData(rowIndex, "transClntNo");
        scwin.f_openCommonPopUp(2, vTransClntNo, "", "T", "T", rowIndex);
    } */
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
	if (!scwin.cfCanOpenPopup(inObj, pairObj))
		return;															// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);											// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);										// inObj가 코드 필드일 경우 팝업
	if (isCode == null || isCode == true)
		scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
																		// inObj가 코드명 필드일 경우 팝업
	else
		scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};
//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
	//변경한 데이터가 있는지 체크한다.(각 dataSet 변경검사)
    if ( ds_tr274.getModifiedIndex().length == 0 ) {
	  $c.gus.cfAlertMsg(MSG_CM_ERR_001, ['입고등록 그리드'] );	//변경된 정보가 없습니다.
	  return;
	}
    if( !await $c.gus.cfValidate(gr_tr274, null, true) ) return;


	//----- Add.2006.02.21 RowStatus가 insert인 "주유소코드" 마감여부 체크(저장가능여부 return)
	if( !await scwin.f_chkJobCloseYN() ) {
		//MSG_CM_ERR_041   =  "@은(는) @할 수 없습니다.";
		$c.gus.cfAlertMsg(MSG_CM_ERR_041, [ '마감여부가 [마감중]또는 [마감완료]인 경우','저장']);  
		return false;
	}

    var chkRowStatus= "";
	//----- 입고수량 체크
	for( let i=0; i<ds_tr274.getRowCount(); i++ ) {
		if( ds_tr274.getCellData( i, "inQty" ) == 0 ){
			$c.gus.cfAlertMsg("입력된 입고수량이 없습니다.");
			return;
		}	
        chkRowStatus = ds_tr274.getRowStatus(i);
        if( chkRowStatus=="U" || chkRowStatus=="C" || chkRowStatus=="D" ){//RowStatus:1(Update),2(Insert),3(Delete)
			// 입고일자 체크[미래(당일 이후)자료 입력  불가]
			if( ds_tr274.getCellData( i, "inDt" ) > scwin.strCurDate ) {
				$c.gus.cfAlertMsg(MSG_CM_ERR_014, ["입고일자", "오늘(" + scwin.strCurDate +")" ] );
				return;
			}				  
		}
	}

    if( await $c.win.confirm(MSG_CM_CRM_001) == true ) { //저장하시겠습니까?
	    $c.sbm.execute(sbm_Save);
    }
};

scwin.sbm_Save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        scwin.f_Retrieve();
    }
};


//-------------------------------------------------------------------------
// RowStatus가 insert인 "주유소 거래처별" 마감여부 체크
//-------------------------------------------------------------------------
scwin.f_chkJobCloseYN = async function () {
	var pReqKind 	= "CUR";	// 마감요청구분
	var pCloseYM 	= "";		// 마감년월	---------------> "기준일자" 넣어줌
	var pCloseDD 	= "00";		// 마감일
	var pWorkNo 	= "TR25";	// 작업번호    
	var pMgntNo		= "";		// 관리번호    	---------------> "주유소별 거래처" 거래처
	var pRtnKind 	= "";		// 리턴구분
	var pDualChkYN 	= "";		// 작업마감+선행마감체크 구분
	var isCloseYN	= "";		// 마감구분코드	
	var editNoneCnt = 0;


	//Filtering된  row갯수 만큼,, 루프돌리기
	for( let j=0; j<ds_tr274.getRowCount(); j++ ) {
		if( ds_tr274.getRowStatus(j) != "R" ) {	// as-is 상태값(0: Normal, 1: Insert, 2: Update, 3: Delete)
			pCloseYM= ds_tr274.getCellData( j,  "inDt" );		    //입고일자
			pMgntNo	= ds_tr274.getCellData( j,  "oilStatClntNo" );	//주유소코드(거래처)

			isCloseYN = await udc_check.cfJobCloseYN(pReqKind,pCloseYM.substring(0,6),pCloseDD,pWorkNo,pMgntNo,pRtnKind,pDualChkYN);
			ds_tr274.setCellData( j,  "closeClsCd" , isCloseYN);
			//edit불가능 할 경우, cnt를 1씩 증가 한다. "cnt>0"이면 저장불가능.
			if( (isCloseYN != "1") && (isCloseYN != "DNF") ){
				editNoneCnt += 1;
			}
		}
	}

	if( editNoneCnt > 0 ) {	//"cnt>0"이면 저장불가능.
		return false;
	} else {				    //"cnt==0"이면 저장가능.
		return true;
	}
};

//-------------------------------------------------------------------------
// 그리드 : 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = async function (){
    var rowPos =  ds_tr274.insertRow();

    ds_tr274.setCellData(rowPos, "inDt", ed_endDt.getValue());
    ds_tr274.setCellData(rowPos, "homeClsCd", lc_homeClsCd.getValue());
    ds_tr274.setCellData(rowPos, "oilStatClntNo", lc_oilStatClsCd.getValue());
    ds_tr274.setCellData(rowPos, "selfTransYn", 0);

    if (ed_endDt.getValue() == "") {
    	await scwin.f_colfocus("F", "", rowPos, "inDt");
    } else if (lc_homeClsCd.getValue() == "") {
    	await scwin.f_colfocus("F", "", rowPos, "homeClsCd");
    } else if (lc_oilStatClsCd.getValue() == "") {
    	await scwin.f_colfocus("F", "", rowPos, "oilStatClntNo");
    } else { 	 
        gr_tr274.setFocusedCell(rowPos, "oilCoClntNo", false);  
    }
};

scwin.f_colfocus = async function (gubun, msg, row, colid) {
    if ( gubun == "T" ) {      
        await $c.win.alert(msg);
    }
    gr_tr274.setFocusedCell(row, colid, false);      
};

//-------------------------------------------------------------------------
// 그리드 : 행삭제
//-------------------------------------------------------------------------
scwin.f_DelRow = function (){
	var inUpr = ds_tr274.getCellData(ds_tr274.getRowPosition(), "inUpr");
	var inAmt = ds_tr274.getCellData(ds_tr274.getRowPosition(), "inAmt");

	if( inUpr!=0 && inAmt!=0 ){
		$c.gus.cfAlertMsg("[유류재고집계내역]이 있는 경우에는  행삭제 할 수 없습니다.");
	}else {
		//ds_tr274.DeleteMarked(); //----- Del. 2006.01.21
		// ds_tr274.deleteRow(ds_tr274.getRowPosition());
		if(ds_tr274.getCellData(ds_tr274.getRowPosition(), "fmsYn") == "Y"){
			$c.win.alert("FMS 유류입고 확정을 통해 입력된 내역은 삭제하실수 없습니다.");
			return;
		}

		//---------------------------------------- Add. 2006.01.21 start
		var isCloseYN = ds_tr274.getCellData( ds_tr274.getRowPosition(),  "closeClsCd" );		
		if( (isCloseYN=="1") || (isCloseYN=="DNF") ) {//edit 가능
			//ds_tr274.DeleteMarked();
            ds_tr274.deleteRow(ds_tr274.getRowPosition());
		}else if(isCloseYN=="0") { 
			$c.gus.cfAlertMsg(MSG_CM_ERR_041, [ '마감여부가 [마감중]인 경우','삭제']);  
			return false;
		}else if(isCloseYN=="2") { 
			$c.gus.cfAlertMsg(MSG_CM_ERR_041, [ '마감여부가 [마감완료]인 경우','삭제']);  
			return false;
		}
		//---------------------------------------- Add. 2006.01.21 end
	}
};

//-------------------------------------------------------------------------
// 그리드에서, 칼럼이 PK일 경우 : update 막기, insert는 입력가능하도록 하는 함수
//-------------------------------------------------------------------------	
scwin.f_EditNone = function (pRow) {
	gr_tr274.setCellReadOnly(pRow, "inDt", true);
	gr_tr274.setCellReadOnly(pRow, "homeClsCd", true);
	gr_tr274.setCellReadOnly(pRow, "oilStatClntNo", true);
	gr_tr274.setCellReadOnly(pRow, "oilCoClntNo", true);
};

scwin.f_EditTrue = function (pRow) {
	gr_tr274.setCellReadOnly(pRow, "inDt", false);
	gr_tr274.setCellReadOnly(pRow, "homeClsCd", false);
	gr_tr274.setCellReadOnly(pRow, "oilStatClntNo", false);
	gr_tr274.setCellReadOnly(pRow, "oilCoClntNo", false);    
	gr_tr274.setCellReadOnly(pRow, "selfTransYn", false);
	gr_tr274.setCellReadOnly(pRow, "transClntNo", false);        
};

scwin.f_EditControl = function (Row,Colid) {     
	//Colid == 입고일자, 주유소명, 정유사명	
	if( (Colid=="inDt") || (Colid=="oilStatClntNo") || (Colid=="oilCoClntNo") || (Colid=="homeClsCd")  ) {
		if( Row > 0 ) {
			if( ds_tr274.getRowStatus(ds_tr274.getRowposition()) == "C" ) {//SysStatus----- insert:1, delete:2, update:3
				scwin.f_EditTrue(Row);
			} else {
				scwin.f_EditNone(Row);
			}
		}
	}		

	//Colid == 입고수량
	if( Colid=="inQty" ) {
		if( Row > 0 ) {
			if( ds_tr274.getRowStatus(ds_tr274.getRowposition()) == "C" ) { 
				gr_tr274.setCellReadOnly(Row, "inQty", true);
			} else {
				scwin.f_chkEdit(Row);
			}
		}	
	}
};	  

//-------------------------------------------------------------------------
// "입고단가","입고금액"이 존재할 경우,  "입고수량" 수정하지 못하도록.
//-------------------------------------------------------------------------	
scwin.f_chkEdit = function (Row) {
	var inUpr = ds_tr274.getCellData(Row, 'inUpr');
	var inAmt = ds_tr274.getCellData(Row, 'inAmt');

	if( inUpr!=0 && inAmt!=0 ) {
        gr_tr274.setCellReadOnly(Row, "inQty", true);
	}else {
		//---------------------------------------- Add. 2006.01.21 start
		var isCloseYN = ds_tr274.getCellData( Row,  "closeClsCd" );
		if( (isCloseYN=="1") || (isCloseYN=="DNF") ) {//edit 가능	
            gr_tr274.setCellReadOnly(Row, "inQty", false);
		}else {//edit 불가능
            gr_tr274.setCellReadOnly(Row, "inQty", true);
		}			
		//---------------------------------------- Add. 2006.01.21 end
	}
};

