//-------------------------------------------------------------------------
// "주유소 거래처별" 마감여부 체크 (Add.2006.02.21)
//-------------------------------------------------------------------------
scwin.f_JobCloseYN = async function () {
	var pReqKind 	= "CUR";	// 마감요청구분
	var pCloseYM 	= "";		// 마감년월	---------------> "기준일자" 넣어줌
	var pCloseDD 	= "00";		// 마감일
	var pWorkNo 	= "TR25";	// 작업번호    
	var pMgntNo		= "";		// 관리번호    	---------------> "주유소별 거래처" 거래처
	var pRtnKind 	= "";		// 리턴구분
	var pDualChkYN 	= "";		// 작업마감+선행마감체크 구분
	var isCloseYN	= "";		// 마감구분코드	

	for( let j=0; j < ds_tr274.getRowCount(); j++ ) {					// Filtering된  row갯수 만큼,, 루프돌리기
		pCloseYM= ds_tr274.getCellData( j,  "inDt" );				// 입고일자
		pMgntNo	= ds_tr274.getCellData( j,  "oilStatClntNo" );	// 주유소코드(거래처)

		isCloseYN = await udc_check.cfJobCloseYN(pReqKind,pCloseYM.substring(0,6),pCloseDD,pWorkNo,pMgntNo,pRtnKind,pDualChkYN);
		ds_tr274.setCellData( j,  "closeClsCd" , isCloseYN);
	}
    ds_tr274.modifyAllStatus("R");
};

