scwin.f_Excel = async function() {
   if(ds_tr274.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let gridColCount = 0;
    for(let i = 0; i < gr_tr274.getTotalCol(); i++){
        if(gr_tr274.getColumnVisible(i)==true){
            gridColCount++;
        }
    }

    let str = $c.gus.cfGetFormatStr(ed_stDt.getValue(), "####/##/##");
    let str1 = $c.gus.cfGetFormatStr(ed_endDt.getValue(), "####/##/##");    
    let str2 = lc_homeClsCd.getText(true);
    let str3 = lc_oilStatClsCd.getText(true);
    let str4 = lc_oilStatClntNo.getText(true);

    let startRowIndex = 0;
    let infoArr = [{
        rowIndex : 0,             
        colIndex : 0,            
        colSpan : gridColCount,   
        rowSpan : 1,
        text : "유류입고",
        textAlign : "center",    
        fontface: "돋움체",
        fontSize : 12,
        drawBorder : false,       
        color : "black",          
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 2,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "입고일자 ["+ str +" ~ "+ str1 +"]" ,
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 3,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "소속구분 ["+ str2 +"]" ,
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff" 
    },{        
        rowIndex : 4,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "주유소구분 ["+ str3 +"]" ,
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff"         
    },{        
        rowIndex : 5,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "주유소 ["+ str4 +"]" ,
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff"          
    }]

    const options = {
        fileName: "유류입고.xlsx",
        sheetName: "유류입고",
        startRowIndex : 6,        
        startColumnIndex : 0,
        type : 1,
        hiddenVisible : false
    };
    await $c.data.downloadGridViewExcel(gr_tr274, options, infoArr);
};

//-------------------------------------------------------------------------
// 전표생성 
//-------------------------------------------------------------------------
scwin.f_CreateSlip = async function () {
    var tmpPayClsCd1Cnt = 0;  // 여신 체크 건수 
    var tmpPayClsCd2Cnt = 0;  // 현물 체크 건수

    if( !await scwin.f_chkJobCloseYN() ) {
		//MSG_CM_ERR_041   =  "@은(는) @할 수 없습니다.";
		$c.gus.cfAlertMsg("이미 유류재고집계가 생성되어 전표를생성할 수 없습니다.");  
		return false;
    }

    for( var i=0; i< ds_tr274.getRowCount(); i++ ) {

     	if( ds_tr274.getCellData(i,"chk") == "T" ) {
  	    	if( ds_tr274.getCellData(i,"payClsCd") == "01" ) {
  		    	tmpPayClsCd1Cnt++;
  		    } else if( ds_tr274.getCellData(i,"payClsCd") == "10" ) {
  			    tmpPayClsCd2Cnt++;
  		    }

  		    if( ds_tr274.getCellData(i,"prePaySlipNo") != "" ) {
  			    $c.win.alert( (i+1) +"행은 이미 전표가 존재하여 생성이 불가능합니다.");
  			    return;
  		    }
  		    if( ds_tr274.getCellData(i,"slipDt") == "" ) {
  			    $c.win.alert( (i+1)+"행의 전표일자를 입력해주시기 바랍니다.");
  			    return;
  		    }
  		    if( ds_tr274.getCellData(i,"rmk") == "" ) {
  			    $c.win.alert( (i+1)+"행의 적요를 입력해주시기 바랍니다.");
  			    return;
  		    }
  	    }
    }

    if( tmpPayClsCd1Cnt != 0 ) {
  	    $c.win.alert("거래구분이 여신거래인 경우 전표생성이 불가능 합니다.");
  	    return;
    }

    if( tmpPayClsCd2Cnt == 0 ) {
  	    $c.win.alert("체크된 내역이 존재하지 않습니다.");
  	    return;
    }

    if( await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_009,"전표")) ) {
        $c.sbm.execute(sbm_createSlip);
    }
};

scwin.sbm_createSlip_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        await $c.gus.cfAlertMsg("전표가 성공적으로 생성되었습니다.");	// 성공적으로 저장하였습니다
        scwin.f_Retrieve();
    }
};

//-------------------------------------------------------------------------
// 전표삭제
//-------------------------------------------------------------------------
scwin.f_DeleteSlip = async function () {
    var tmpPayClsCd1Cnt = 0;  // 여신 체크 건수 
    var tmpPayClsCd2Cnt = 0;  // 현물 체크 건수 

    if( !await scwin.f_chkJobCloseYN() ) {
		//MSG_CM_ERR_041   =  "@은(는) @할 수 없습니다.";
		$c.gus.cfAlertMsg("이미 유류재고집계가 생성되어 전표를생성할 수 없습니다.");  
		return false;
    }

    for( var i=0; i< ds_tr274.getRowCount(); i++ ) {
  	    if( ds_tr274.getCellData(i,"chk") == "T" ) {
  		    if( ds_tr274.getCellData(i,"prePaySlipNo") == "" ) {
  			    $c.win.alert("전표번호가 존재하지 않습니다.");
  			    return;
  		    }
  		    if( ds_tr274.getCellData(i,"payClsCd") == "01" ) {
  			    tmpPayClsCd1Cnt++;
  		    } else if( ds_tr274.getCellData(i,"payClsCd") == "10" ) {
  			    tmpPayClsCd2Cnt++;
  		    }
  	    }
    }

    if( tmpPayClsCd1Cnt != 0 ) {
  	    $c.win.alert("거래구분이 여신거래인 경우 전표삭제 불가능 합니다.");
  	    return;
    } 

    if( tmpPayClsCd2Cnt == 0 ) {    
        $c.win.alert("체크된 내역이 존재하지 않습니다.");
        return;  
    }

    if( await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_008,"전표")) ) {
        $c.sbm.execute(sbm_deleteSlip);
    }
};

scwin.sbm_deleteSlip_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        await $c.gus.cfAlertMsg("전표가 성공적으로 삭제되었습니다.");	// 성공적으로 저장하였습니다
        scwin.f_Retrieve();
    }
};

