//-------------------------------------------------------------------------
// 그리드 info - onviewchange
//-------------------------------------------------------------------------
scwin.gr_tr274_onviewchange = function (info) {

    if(info.colId == "selfTransYn") { 
        let opts = scwin.custom_Info("select", "selfTransYn" ); 
        gr_tr274.setCellInputType(info.rowIndex, "selfTransYn", opts);                                
    } 
    if(info.colId == "oilStatClsCd") {  // 주유소구분
        let opts = scwin.custom_Info("select", "oilStatClsCd" ); 
        gr_tr274.setCellInputType(info.rowIndex, "oilStatClsCd", opts);                                
    }  
    if(info.colId == "oilStatClntNo") {  // 주유소
        let opts = scwin.custom_Info("select", "oilStatClntNo" ); 
        gr_tr274.setCellInputType(info.rowIndex, "oilStatClntNo", opts);                                
    }         
    if(info.colId == "oilCoClntNo") {   // 정유사
        let opts = scwin.custom_Info("select", "oilCoClntNo" ); 
        gr_tr274.setCellInputType(info.rowIndex, "oilCoClntNo", opts);                                
    }                
};

//-------------------------------------------------------------------------
// type 에 맞는 info 정보 셋팅
//-------------------------------------------------------------------------
scwin.custom_Info = function(type, colid) {
    let ret = "";

    switch(type) {
        case "select" :
            if (colid = "selfTransYn" ) {
                ret = {
                    inputType : "select",
                    options : {
                        viewType: "icon", chooseOption: true
                    },
                    itemSet : {
                        nodeset: "data:ds_selfTransYn", 
                        label: "selfTransYnNm",
                        value: "selfTransYn"
                    }
                }
            }    
            if (colid = "oilStatClsCd" ) {
                ret = {
                    inputType : "select",
                    options : {
                        viewType: "icon", chooseOption: true
                    },
                    itemSet : {
                        nodeset: "data:dlt_gauceUtil_lc_oilStatClsCd_gr_tr274_oilStatClsCd", 
                        label: "name",
                        value: "code"
                    }
                }
            }    
            if (colid = "oilStatClntNo" ) {
                ret = {
                    inputType : "select",
                    options : {
                        viewType: "icon", chooseOption: true, displayMode: "value delim label"
                    },
                    itemSet : {
                        nodeset: "data:dlt_gauceUtil_lc_oilStatClntNo_gr_tr274_oilStatClntNo", 
                        label: "name",
                        value: "code"
                    }
                }
            }    
            if (colid = "oilCoClntNo" ) {
                ret = {
                    inputType : "select",
                    options : {
                        viewType: "icon", chooseOption: true, displayMode: "value delim label"
                    },
                    itemSet : {
                        nodeset: "data:dlt_gauceUtil_lc_oilCoClntNo_gr_tr274_oilCoClntNo", 
                        label: "name",
                        value: "code"
                    }
                }                                                
            }
        break;
    }    
};  

