//-------------------------------------------------------------------------
// Grid 셀 클릭시 발생 이벤트
//-------------------------------------------------------------------------
scwin.gr_tr274_oncellclick = function (rowIndex, columnIndex, columnId) {
	//Colid == 입고일자, 주유소명, 정유사명
    if( columnId == "inDt" || columnId == "oilStatClntNo" || columnId == "oilCoClntNo" || columnId == "homeClsCd" ) {
		if( rowIndex >= 0 ) { 
			if( ds_tr274.getRowStatus(rowIndex) == "C" ) {//SysStatus----- insert:1, delete:2, update:3                
				// scwin.f_EditTrue(rowIndex);
                gr_tr274.setCellReadOnly(rowIndex, "inDt", false);
                gr_tr274.setCellReadOnly(rowIndex, "homeClsCd", false);
                gr_tr274.setCellReadOnly(rowIndex, "oilStatClntNo", false);
                gr_tr274.setCellReadOnly(rowIndex, "oilCoClntNo", false);    
                gr_tr274.setCellReadOnly(rowIndex, "selfTransYn", false);
                gr_tr274.setCellReadOnly(rowIndex, "transClntNo", false); 
			} else {
				// scwin.f_EditNone(rowIndex);
                gr_tr274.setCellReadOnly(rowIndex, "inDt", true);
                gr_tr274.setCellReadOnly(rowIndex, "homeClsCd", true);
                gr_tr274.setCellReadOnly(rowIndex, "oilStatClntNo", true);
                gr_tr274.setCellReadOnly(rowIndex, "oilCoClntNo", true);
			}
		}
	}		

	//Colid == 입고수량
    if( columnId == "inQty" ) {
		if( rowIndex >= 0 ) {
			if( ds_tr274.getRowStatus(rowIndex) == "C" ) { 
				gr_tr274.setCellReadOnly(rowIndex, "inQty", false);
			} else {
				scwin.f_chkEdit(rowIndex);
			}
		}	
	}

    if( columnId == "selfTransYn" || columnId == "chk" ) {
        if( ds_tr274.getCellData(rowIndex, columnId) == ds_tr274.getOriginalCellData(rowIndex, columnId) ) {
            ds_tr274.modifyRowStatus(rowIndex, "R");
        }
    }
};
